def transition(state, action):
    s = dict(state)
    # Copy nested mappings so we never mutate the caller's state in place.
    env = dict(s.get("envelopes", {}))
    alloc = dict(s.get("allocations", {}))
    s["envelopes"] = env
    s["allocations"] = alloc

    name = action.get("name")
    params = action.get("params") or {}
    names = sorted(env)  # deterministic order for defaulted targets

    def amount_of(raw, default):
        try:
            v = float(raw)
        except (TypeError, ValueError):
            return float(default)
        return v if v > 0 else float(default)

    if name == "spend":
        target = params.get("envelope")
        if target not in env:
            target = names[0] if names else None
        amt = amount_of(params.get("amount"), 50.0)
        if target is not None:
            # No overdraft: you can only pay what the envelope holds; any
            # shortfall is simply not spent.
            paid = min(amt, env[target])
            env[target] = round(env[target] - paid, 2)
            s["spent_total"] = round(s.get("spent_total", 0.0) + paid, 2)
        s["last"] = "spend"

    elif name == "transfer":
        src = params.get("from")
        dst = params.get("to")
        if src not in env:
            src = names[0] if names else None
        if dst not in env or dst == src:
            dst = next((n for n in names if n != src), None)
        amt = amount_of(params.get("amount"), 25.0)
        if src is not None and dst is not None and src != dst:
            # Conserve total funds: move only what the source can give.
            moved = min(amt, env[src])
            env[src] = round(env[src] - moved, 2)
            env[dst] = round(env[dst] + moved, 2)
        s["last"] = "transfer"

    elif name == "rollover":
        # Start a new period: each envelope keeps whatever is left (the rollover)
        # and is then topped up by its monthly allocation.
        carried = 0.0
        for k in env:
            carried += env[k]
            env[k] = round(env[k] + alloc.get(k, 0.0), 2)
        s["period"] = int(s.get("period", 1)) + 1
        s["rollover_total"] = round(s.get("rollover_total", 0.0) + carried, 2)
        s["last"] = "rollover"

    return s

