def perceive(data):
    out = {}
    env = {}
    for line in str(data).splitlines():
        if ":" not in line:
            continue
        key, val = line.split(":", 1)
        key = key.strip().lower()
        val = val.strip().replace("$", "").replace(",", "")
        if not key:
            continue
        if key == "period":
            try:
                out["period"] = int(float(val))
            except (TypeError, ValueError):
                pass
        else:
            try:
                env[key] = round(float(val), 2)
            except (TypeError, ValueError):
                pass
    if env:
        out["envelopes"] = env
    return out
